using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class ConfigResource
{
    [McpServerResource(UriTemplate = "config://app/settings", Name = "App Settings",
        MimeType = "application/json")]
    [Description("Returns the current application configuration as JSON")]
    public static string GetAppSettings()
    {
        var config = new
        {
            Environment = "Production",
            MaxRetries = 3,
            TimeoutSeconds = 30,
            Features = new { DarkMode = true, BetaFeatures = false }
        };

        return JsonSerializer.Serialize(config, new JsonSerializerOptions { WriteIndented = true });
    }

    [McpServerResource(UriTemplate = "config://app/version", Name = "App Version",
        MimeType = "text/plain")]
    [Description("Returns the current application version")]
    public static string GetVersion() => "1.0.0";
}

using System.ComponentModel;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class ConfigTools
{
    [McpServerTool, Description("Validates a configuration key-value pair against known rules.")]
    public static string ValidateConfig(
        [Description("Configuration key name (e.g., 'MaxRetries')")] string key,
        [Description("Proposed value to validate")] string value)
    {
        return key.ToLowerInvariant() switch
        {
            "maxretries" when int.TryParse(value, out var n) && n is >= 1 and <= 10
                => $"✓ '{key}={value}' is valid.",
            "maxretries"
                => $"✗ '{key}={value}' is invalid. MaxRetries must be an integer between 1 and 10.",
            "timeoutseconds" when int.TryParse(value, out var n) && n is >= 5 and <= 300
                => $"✓ '{key}={value}' is valid.",
            "timeoutseconds"
                => $"✗ '{key}={value}' is invalid. TimeoutSeconds must be between 5 and 300.",
            _ => $"⚠ Unknown configuration key '{key}'. Known keys: MaxRetries, TimeoutSeconds."
        };
    }
}

